insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('7000649e-38e3-5b4f-990b-1c62891a7081', 'news', 'published', 'Travel', null, 'https://apnews.com/article/trump-world-cup-visa-bonds-a3a165fb5c2d215c5cd237d7a2e783ad', '2026-05-13T16:47:00+00:00') on conflict (id) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('7000649e-38e3-5b4f-990b-1c62891a7081', 'en', 'world-cup-visa-bond-waiver-ticket-holders', 'World Cup ticket holders get a visa-bond waiver', 'The U.S. is waiving visa bonds for some World Cup ticket holders from qualified countries, easing one travel barrier before the tournament.', 'A U.S. visa-bond requirement will no longer apply to certain foreign fans who hold FIFA World Cup tickets and come from qualified countries affected by the bond program. AP reported that the exemption covers ticket buyers from Algeria, Cape Verde, Ivory Coast, Senegal and Tunisia.\n\nFor those supporters, the waiver removes a major cash-flow obstacle, but it does not replace the normal visa process or guarantee entry. Travelers still need to follow consular instructions, appointment timing and any country-specific restrictions.\n\nCupMate users should keep FIFA ticket proof, visa appointment records and travel documents together. International supporters should also preserve refundable options where possible because entry guidance can still change close to kickoff.', 'World Cup ticket holders get a visa-bond waiver', 'The U.S. is waiving visa bonds for some World Cup ticket holders from qualified countries, easing one travel barrier before the tournament.') on conflict (article_id, language_code) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('7000649e-38e3-5b4f-990b-1c62891a7081', 'ru', 'boleschiki-chm-s-biletami-poluchat-isklyuchenie-po-vizovym-bondam', 'Болельщики ЧМ с билетами получат исключение по визовым bond-платежам', 'США отменяют визовые bond-платежи для части владельцев билетов из стран-участниц, снижая один из барьеров поездки.', 'Требование о визовом bond-платеже больше не будет применяться к части иностранных болельщиков, у которых есть билеты FIFA и гражданство стран-участниц, попавших под эту программу. AP сообщило, что исключение касается покупателей билетов из Алжира, Кабо-Верде, Кот-д’Ивуара, Сенегала и Туниса.\n\nДля этих болельщиков решение убирает крупный финансовый барьер, но не заменяет обычную визовую процедуру и не гарантирует въезд. Нужно по-прежнему следить за консульскими инструкциями, сроками записи и ограничениями по конкретной стране.\n\nВ CupMate такую поездку стоит планировать как документный маршрут: хранить подтверждение билета FIFA, статус визовой записи и travel documents вместе, а по возможности выбирать возвратные бронирования.', 'Болельщики ЧМ с билетами получат исключение по визовым bond-платежам', 'США отменяют визовые bond-платежи для части владельцев билетов из стран-участниц, снижая один из барьеров поездки.') on conflict (article_id, language_code) do nothing;

insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('4ff33ca9-ca83-5461-8ad2-c11ce2f8103a', 'news', 'published', 'Tickets', null, 'https://as.com/us/futbol/mundial/california-pide-respuestas-a-fifa-por-irregularidades-en-venta-de-boletos-al-mundial-f202605-n/', '2026-05-14T18:32:00+00:00') on conflict (id) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('4ff33ca9-ca83-5461-8ad2-c11ce2f8103a', 'en', 'california-fifa-ticketing-practices-letter', 'California asks FIFA for answers on World Cup ticketing', 'California Attorney General Rob Bonta has asked FIFA for information after reports of potentially misleading World Cup ticketing practices.', 'California Attorney General Rob Bonta has sent FIFA a request for information about World Cup ticketing practices after reports that some buyers may have received seats different from what they believed they were purchasing.\n\nFor fans, the practical response is to preserve the purchase trail. Keep order confirmations, seat-category language, screenshots from the purchase flow, payment receipts and later assignment emails together. That record matters if a dispute has to go through FIFA support, a payment provider or a consumer-protection office.\n\nCalifornia is a major tournament market, with matches in Los Angeles and the San Francisco Bay Area. CupMate users should separate ticket certainty from travel excitement: confirm official ticket status before locking the rest of a group itinerary.', 'California asks FIFA for answers on World Cup ticketing', 'California Attorney General Rob Bonta has asked FIFA for information after reports of potentially misleading World Cup ticketing practices.') on conflict (article_id, language_code) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('4ff33ca9-ca83-5461-8ad2-c11ce2f8103a', 'ru', 'kaliforniya-zaprosila-u-fifa-otvety-po-prodazhe-biletov', 'Калифорния запросила у FIFA ответы по продаже билетов ЧМ', 'Генпрокурор Калифорнии Роб Бонта запросил информацию после сообщений о возможных проблемах с ticketing practices.', 'Генеральный прокурор Калифорнии Роб Бонта направил FIFA запрос о практиках продажи билетов на Чемпионат мира после сообщений, что часть покупателей могла получить места не так, как ожидала при покупке.\n\nДля болельщиков главный вывод практический: нужно сохранять весь след покупки. Подтверждения заказа, описание категории места, скриншоты процесса покупки, платежные документы и письма о назначении мест лучше держать вместе. Это пригодится при обращении в FIFA, платежный сервис или consumer-protection office.\n\nКалифорния принимает 14 матчей турнира в Лос-Анджелесе и районе Сан-Франциско, поэтому тема важна для большого числа поездок. В CupMate такие планы стоит строить только после подтверждения официального статуса билета.', 'Калифорния запросила у FIFA ответы по продаже билетов ЧМ', 'Генпрокурор Калифорнии Роб Бонта запросил информацию после сообщений о возможных проблемах с ticketing practices.') on conflict (article_id, language_code) do nothing;

insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('6b2bf7be-37f9-5b6b-8fda-991001ab0c64', 'news', 'published', 'Teams', null, 'https://www.fifa.com/en/tournaments/mens/worldcup/canadamexicousa2026/articles/france-world-cup-squad-named', '2026-05-14T18:43:00+00:00') on conflict (id) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('6b2bf7be-37f9-5b6b-8fda-991001ab0c64', 'en', 'france-names-world-cup-squad-risser', 'France names World Cup squad with Risser surprise', 'Didier Deschamps'' 26-player France list leans on elite attacking depth and includes a first major-tournament call-up for goalkeeper Robin Risser.', 'France''s World Cup squad is built around familiar firepower, but the selection still delivered a fresh storyline with Robin Risser earning a place after his breakthrough season. For CupMate users, the update matters because squad news shapes saved-team alerts, expected lineups and the way fans plan around France''s group-stage matches.', 'France names World Cup squad with Risser surprise', 'Didier Deschamps'' 26-player France list leans on elite attacking depth and includes a first major-tournament call-up for goalkeeper Robin Risser.') on conflict (article_id, language_code) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('6b2bf7be-37f9-5b6b-8fda-991001ab0c64', 'ru', 'frantsiya-nazvala-zayavku-na-chm-s-risserom', 'Франция назвала заявку на ЧМ с неожиданным вызовом Риссера', 'Дидье Дешам сохранил мощную атакующую основу и добавил свежий сюжет: вратарь Робин Риссер получил место в заявке.', 'Франция подходит к Чемпионату мира с ожидаемо сильной обоймой в атаке, но заявка всё равно дала новый повод для обсуждений: Робин Риссер получил вызов после яркого клубного сезона. Для болельщиков это не просто список фамилий, а основа для прогнозов состава, уведомлений по сборной и планирования матчей Франции в CupMate.', 'Франция назвала заявку на ЧМ с неожиданным вызовом Риссера', 'Дидье Дешам сохранил мощную атакующую основу и добавил свежий сюжет: вратарь Робин Риссер получил место в заявке.') on conflict (article_id, language_code) do nothing;

insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('f08da9ef-c705-5a9d-84c8-356f13421d97', 'news', 'published', 'Teams', null, 'https://www.fifa.com/en/articles/carlo-ancelotti-brazil-contract-extension', '2026-05-14T18:12:00+00:00') on conflict (id) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('f08da9ef-c705-5a9d-84c8-356f13421d97', 'en', 'brazil-ancelotti-extends-2030-world-cup', 'Brazil extends Carlo Ancelotti through 2030', 'Brazil moved before the tournament to keep Carlo Ancelotti in charge through the next World Cup cycle.', 'Brazil''s federation has extended Carlo Ancelotti''s contract through the 2030 World Cup, a major continuity signal before the 2026 tournament begins. For fans, the move adds context to Brazil''s squad choices: the coach is not only managing the coming month, but also shaping a longer project.', 'Brazil extends Carlo Ancelotti through 2030', 'Brazil moved before the tournament to keep Carlo Ancelotti in charge through the next World Cup cycle.') on conflict (article_id, language_code) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('f08da9ef-c705-5a9d-84c8-356f13421d97', 'ru', 'braziliya-prodlila-kontrakt-anchelotti-do-2030', 'Бразилия продлила контракт Анчелотти до 2030 года', 'Перед стартом турнира сборная Бразилии закрепила тренерскую линию сразу на следующий цикл.', 'Бразилия продлила контракт Карло Анчелотти до Чемпионата мира 2030 года. Это важный сигнал перед турниром 2026: тренер выбирает состав не только под ближайший месяц, но и в рамках более длинного проекта, поэтому решения по игрокам получают дополнительный контекст.', 'Бразилия продлила контракт Анчелотти до 2030 года', 'Перед стартом турнира сборная Бразилии закрепила тренерскую линию сразу на следующий цикл.') on conflict (article_id, language_code) do nothing;

insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('e66941c1-0a12-5623-9be4-f01541335834', 'news', 'published', 'Stadiums', null, 'https://inside.fifa.com/news/pitch-installation-world-cup-2026-final-new-york-new-jersey', '2026-05-08T15:00:00+00:00') on conflict (id) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('e66941c1-0a12-5623-9be4-f01541335834', 'en', 'metlife-final-natural-grass-installation', 'Natural grass installed at the World Cup final venue', 'FIFA says pitch installation is complete at the New York New Jersey stadium that will stage the 2026 final.', 'The natural grass surface is now in place at the New York New Jersey final venue, one of the most important infrastructure milestones before the tournament. The work is part of a broader pitch programme across all 16 host stadiums, and it matters for both match quality and player safety.', 'Natural grass installed at the World Cup final venue', 'FIFA says pitch installation is complete at the New York New Jersey stadium that will stage the 2026 final.') on conflict (article_id, language_code) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('e66941c1-0a12-5623-9be4-f01541335834', 'ru', 'na-stadione-finala-chm-ulozhili-naturalnyy-gazon', 'На стадионе финала ЧМ уложили натуральный газон', 'FIFA сообщила о завершении ключевого этапа подготовки поля на арене Нью-Йорк / Нью-Джерси.', 'Натуральное покрытие на стадионе финала в Нью-Йорке / Нью-Джерси уже уложено. Для турнира это один из главных инфраструктурных этапов: качество газона влияет на скорость игры, безопасность футболистов и общее впечатление от решающих матчей.', 'На стадионе финала ЧМ уложили натуральный газон', 'FIFA сообщила о завершении ключевого этапа подготовки поля на арене Нью-Йорк / Нью-Джерси.') on conflict (article_id, language_code) do nothing;

insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('5cc4691f-84a4-555d-a354-d2efeba98d30', 'news', 'published', 'Transport', null, 'https://www.axios.com/local/seattle/2026/05/13/seattle-world-cup-2026-traffic-light-rail-ferry-lumen-field-road-closures', '2026-05-13T12:00:00+00:00') on conflict (id) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('5cc4691f-84a4-555d-a354-d2efeba98d30', 'en', 'seattle-world-cup-transit-plan', 'Seattle prepares for World Cup transit crunch', 'Seattle is warning residents and fans to expect road closures, crowded light rail and packed ferries around matches at Lumen Field.', 'Seattle''s World Cup plan is moving from abstract preparation to practical match-day logistics. With six matches set for Lumen Field, fans should expect a transit-first approach, perimeter road closures and heavy pressure on trains, ferries and downtown corridors.', 'Seattle prepares for World Cup transit crunch', 'Seattle is warning residents and fans to expect road closures, crowded light rail and packed ferries around matches at Lumen Field.') on conflict (article_id, language_code) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('5cc4691f-84a4-555d-a354-d2efeba98d30', 'ru', 'sietl-gotovitsya-k-transportnoy-nagruzke-vo-vremya-chm', 'Сиэтл готовится к транспортной нагрузке во время ЧМ', 'Город предупреждает о перекрытиях, перегруженном light rail и большом спросе на паромы вокруг матчей на Lumen Field.', 'Подготовка Сиэтла к Чемпионату мира переходит в практическую фазу. Шесть матчей на Lumen Field означают приоритет общественного транспорта, перекрытия вокруг стадиона и серьёзную нагрузку на поезда, паромы и центральные улицы. Болельщикам лучше заранее сохранять маршрут и запас по времени.', 'Сиэтл готовится к транспортной нагрузке во время ЧМ', 'Город предупреждает о перекрытиях, перегруженном light rail и большом спросе на паромы вокруг матчей на Lumen Field.') on conflict (article_id, language_code) do nothing;

insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('4fb61ac5-3dd2-54bd-abbb-3913d42759a0', 'news', 'published', 'Travel', null, 'https://apnews.com/article/d317e214b976c7247b82d88d395e058c', '2026-05-14T15:04:00+00:00') on conflict (id) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('4fb61ac5-3dd2-54bd-abbb-3913d42759a0', 'en', 'mexico-city-azteca-world-cup-guide', 'Mexico City readies culture, food and crowds for the opener', 'Mexico City is preparing to showcase its food, history and scale while managing congestion around Estadio Azteca.', 'Mexico City will be one of the defining host-city stories of the tournament: a huge, layered capital welcoming fans to the opening match at Estadio Azteca. The practical side is just as important as the cultural appeal, from Metro and light-rail routes to crowd management around the stadium.', 'Mexico City readies culture, food and crowds for the opener', 'Mexico City is preparing to showcase its food, history and scale while managing congestion around Estadio Azteca.') on conflict (article_id, language_code) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('4fb61ac5-3dd2-54bd-abbb-3913d42759a0', 'ru', 'mehiko-gotovit-kulturu-edu-i-potoki-bolelschikov-k-otkrytiyu-chm', 'Мехико готовит культуру, еду и потоки болельщиков к открытию ЧМ', 'Город будет показывать свою кухню и историю, параллельно решая вопросы трафика вокруг Эстадио Ацтека.', 'Мехико станет одной из главных городских историй турнира: огромная столица примет болельщиков на матч открытия на Эстадио Ацтека. Культурная часть выглядит мощно, но практические детали не менее важны: метро, легкорельсовые маршруты, точки питания и управление потоками около стадиона.', 'Мехико готовит культуру, еду и потоки болельщиков к открытию ЧМ', 'Город будет показывать свою кухню и историю, параллельно решая вопросы трафика вокруг Эстадио Ацтека.') on conflict (article_id, language_code) do nothing;

insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('a3d5772e-fe6d-5e18-9947-37b48088976b', 'news', 'published', 'Music', null, 'https://www.fifa.com/en/tournaments/mens/worldcup/canadamexicousa2026/articles/madonna-shakira-bts-co-headline-historic-final-halftime-show', '2026-05-14T16:00:00+00:00') on conflict (id) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('a3d5772e-fe6d-5e18-9947-37b48088976b', 'en', 'world-cup-final-halftime-show-lineup', 'World Cup final adds a first halftime show', 'FIFA confirmed Madonna, Shakira and BTS for the first World Cup final halftime show at the New York New Jersey venue.', 'The 2026 final will add a new entertainment layer: a halftime show headlined by Madonna, Shakira and BTS and tied to the FIFA Global Citizen Education Fund. For fans in New York New Jersey, the announcement turns the final into an even larger event-planning challenge around timing, entry and post-match movement.', 'World Cup final adds a first halftime show', 'FIFA confirmed Madonna, Shakira and BTS for the first World Cup final halftime show at the New York New Jersey venue.') on conflict (article_id, language_code) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('a3d5772e-fe6d-5e18-9947-37b48088976b', 'ru', 'final-chm-vpervye-poluchit-halftime-show', 'Финал ЧМ впервые получит halftime show', 'FIFA подтвердила музыкальное шоу в перерыве финала в Нью-Йорке / Нью-Джерси с Мадонной, Шакирой и BTS.', 'Финал Чемпионата мира 2026 получит новый развлекательный слой: FIFA анонсировала первое шоу в перерыве финала с Мадонной, Шакирой и BTS, связанное с FIFA Global Citizen Education Fund. Для болельщиков это делает день финала ещё более насыщенным и требует внимательнее планировать вход, тайминг и обратный маршрут.', 'Финал ЧМ впервые получит halftime show', 'FIFA подтвердила музыкальное шоу в перерыве финала в Нью-Йорке / Нью-Джерси с Мадонной, Шакирой и BTS.') on conflict (article_id, language_code) do nothing;

