insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('38bebbad-aef4-5a30-9ab9-4127d8c94c63', 'news', 'published', 'Teams', null, 'https://www.fifa.com/en/articles/tunisia-squad-named-sabri-lamouchi', '2026-05-15T12:00:00+00:00') on conflict (id) do update set status = excluded.status, category = excluded.category, source_url = excluded.source_url, published_at = excluded.published_at;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('38bebbad-aef4-5a30-9ab9-4127d8c94c63', 'en', 'tunisia-world-cup-squad-khedira-rebuild', 'Tunisia''s World Cup squad points to a Lamouchi rebuild before Group F', 'Sabri Lamouchi has named a much-changed Tunisia squad for the World Cup, with Rani Khedira among the notable new pieces before Group F.', 'Tunisia''s World Cup squad carries a clear reset message. FIFA reported that Sabri Lamouchi has selected a 26-player group that differs sharply from the 2025 Africa Cup of Nations roster, with Rani Khedira set for his first official competitive Tunisia appearance and Group F matches waiting against Sweden, Japan and the Netherlands.

Lamouchi has not simply rolled forward the last tournament group. The inclusion of new profiles, including Khedira, shows Tunisia trying to refresh parts of the team before entering a group that requires different types of match plans.

Tunisia''s first two matches are both in Monterrey, against Sweden on June 14 and Japan on June 20. The third match sends fans to Kansas City for Tunisia against the Netherlands on June 25, a move that turns this campaign into both a football and travel-planning challenge.

The practical question is how quickly Tunisia''s newer pieces settle. Squad changes can alter formation, set-piece roles and captaincy dynamics, which affects how supporters interpret warm-up news and whether a group-stage lineup is stable or still being tested.

CupMate users following Tunisia should treat Monterrey as a base and Kansas City as a separate trip segment. Save both stadium routes, monitor official squad confirmation on June 2 and avoid assuming Africa Cup of Nations lineups still describe this team.', 'Tunisia''s World Cup squad points to a Lamouchi rebuild before Group F', 'Sabri Lamouchi has named a much-changed Tunisia squad for the World Cup, with Rani Khedira among the notable new pieces before Group F.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('38bebbad-aef4-5a30-9ab9-4127d8c94c63', 'ru', 'tunisiya-sostav-chm-perestroika-lamushi', 'Состав Туниса на ЧМ показывает перестройку Ламуши', 'Сабри Ламуши назвал заметно обновленную заявку Туниса, где одним из новых элементов стал Рани Хедира.', 'Состав Туниса на Чемпионат мира выглядит как явный сигнал перестройки. FIFA сообщает, что Сабри Ламуши выбрал группу из 26 игроков, которая заметно отличается от заявки на Кубок Африки 2025 года. Среди важных новых фигур — Рани Хедира, готовящийся к первому официальному турниру за Тунис.

Маршрут группы F удобен только на первый взгляд. Тунис сыграет два первых матча в Монтеррее: 14 июня против Швеции и 20 июня против Японии. Затем болельщикам понадобится отдельный план на Канзас-Сити, где 25 июня пройдет матч с Нидерландами.

В CupMate болельщикам Туниса стоит сохранить Монтеррей как базовый блок поездки, отдельно добавить Канзас-Сити и следить за финальным подтверждением состава FIFA 2 июня. Старые ориентиры по заявке уже не полностью описывают эту команду.', 'Состав Туниса на ЧМ показывает перестройку Ламуши', 'Сабри Ламуши назвал заметно обновленную заявку Туниса, где одним из новых элементов стал Рани Хедира.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;

insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('a60a94d8-0745-5eb5-9d52-34c104ab0550', 'news', 'published', 'Transport', null, 'https://www.axios.com/local/philadelphia/2026/05/13/world-cup-parking-restrictions-lemon-hill-fan-festival', '2026-05-13T12:00:00+00:00') on conflict (id) do update set status = excluded.status, category = excluded.category, source_url = excluded.source_url, published_at = excluded.published_at;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('a60a94d8-0745-5eb5-9d52-34c104ab0550', 'en', 'philadelphia-fan-festival-parking-permits', 'Philadelphia adds parking permits around its World Cup Fan Festival', 'Axios reports that Philadelphia will require special permits near Lemon Hill as the city''s World Cup Fan Festival prepares for daily crowds.', 'Philadelphia is moving from general Fan Festival planning to neighborhood-level traffic control. Axios Philadelphia reported that non-resident vehicles parking near Lemon Hill will need a special permit from June 11 through July 19, with the festival expected to draw roughly 15,000 to 20,000 people per day in Fairmount Park.

The permit zone is designed to keep tournament traffic from overwhelming residential streets around Fairmount Park. Axios reported that the zone will cover parts of Fairmount and Brewerytown, with increased patrols and possible towing for violations.

Philadelphia''s Fan Festival is one of the biggest no-ticket World Cup experiences in the United States because it runs for the full tournament. That makes parking pressure a daily issue, not a one-off match-day problem around Lincoln Financial Field.

The system also affects locals. Residents with regular parking permits still need special approval, and businesses can request visitor day passes. That means fans staying with friends or short-term rentals near the festival should confirm parking rules before arrival.

CupMate users should save the Fan Festival as a transit-first destination. If the plan includes a match at the South Philadelphia stadium and a Lemon Hill visit on the same day, treat them as separate mobility zones and avoid relying on a single parking strategy.', 'Philadelphia adds parking permits around its World Cup Fan Festival', 'Axios reports that Philadelphia will require special permits near Lemon Hill as the city''s World Cup Fan Festival prepares for daily crowds.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('a60a94d8-0745-5eb5-9d52-34c104ab0550', 'ru', 'philadelphia-fan-festival-spetsrazresheniya-na-parkovku', 'Philadelphia вводит спецразрешения на парковку у Fan Festival', 'По данным Axios, вокруг Lemon Hill введут особую parking-зону на все дни Чемпионата мира.', 'Philadelphia переходит от общей подготовки Fan Festival к точному контролю улиц вокруг Lemon Hill. Axios Philadelphia сообщает, что с 11 июня по 19 июля машины нерезидентов в специальной зоне рядом с фестивалем должны будут иметь отдельное разрешение.

Для болельщиков это означает простой вывод: не стоит ехать к Lemon Hill на машине без заранее подтвержденного плана. Фестиваль может собирать 15-20 тысяч человек в день, поэтому парковка станет ежедневной проблемой, а не только вопросом матчей на стадионе.

В CupMate Fan Festival в Philadelphia лучше сохранять как transit-first точку: SEPTA, PHLASH, rideshare или пешие связки. Если в один день есть и матч, и фестиваль, их нужно планировать как две разные транспортные зоны.', 'Philadelphia вводит спецразрешения на парковку у Fan Festival', 'По данным Axios, вокруг Lemon Hill введут особую parking-зону на все дни Чемпионата мира.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;

insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('5ea53244-db3b-5b0f-9b4a-4d3a200a3c8d', 'news', 'published', 'Fan Experience', null, 'https://elpais.com/us/2026-05-15/los-angeles-enciende-la-fiebre-mundialista-con-zonas-fan-fest-ubicadas-en-la-playa-y-recintos-iconicos-de-la-ciudad.html', '2026-05-15T12:00:00+00:00') on conflict (id) do update set status = excluded.status, category = excluded.category, source_url = excluded.source_url, published_at = excluded.published_at;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('5ea53244-db3b-5b0f-9b4a-4d3a200a3c8d', 'en', 'los-angeles-fan-fest-neighborhood-zones', 'Los Angeles World Cup fan zones spread beyond the Coliseum', 'El Pais reports that Los Angeles will pair a paid Coliseum Fan Festival with neighborhood fan zones across the region during the World Cup.', 'Los Angeles is taking a hybrid approach to World Cup watching. El Pais US reported that the official FIFA Fan Festival at the Los Angeles Memorial Coliseum will run June 11-14 with paid entry, while a wider network of neighborhood fan zones will bring match broadcasts and cultural programming to sites such as Original Farmers Market, Union Station, Hansen Dam, Magic Johnson Park, Venice Beach and Fairplex.

Los Angeles is not relying on one central public-viewing site for the full tournament. The opening stretch is built around the Coliseum, while later dates spread across the region. That gives fans more options but also makes planning more fragmented.

El Pais listed neighborhood sites including Original Farmers Market from June 18-21, Union Station from June 25-28, Hansen Dam Lake from July 2-5, Magic Johnson Park from July 4-5, Whittier Narrows from July 9-11, Venice Beach on July 11 and Fairplex across selected dates in mid-July.

Los Angeles distances can turn a casual watch-party choice into a major logistics decision. A beach event, a Union Station event and a Fairplex event are not interchangeable, especially for fans also planning SoFi Stadium match days in Inglewood.

CupMate users should save Los Angeles watch sites by date, not just by name. The best plan is to pair each fan zone with a transit route, a realistic rideshare pickup area and a backup venue in case capacity or security lines change the day.', 'Los Angeles World Cup fan zones spread beyond the Coliseum', 'El Pais reports that Los Angeles will pair a paid Coliseum Fan Festival with neighborhood fan zones across the region during the World Cup.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('5ea53244-db3b-5b0f-9b4a-4d3a200a3c8d', 'ru', 'los-angeles-fan-zony-vyydut-za-predely-coliseum', 'Fan zones Лос-Анджелеса выйдут за пределы Coliseum', 'El Pais пишет, что город соединит платный Fan Festival в Coliseum с сетью районных площадок по всему региону.', 'Лос-Анджелес выбрал гибридную модель фанатского просмотра Чемпионата мира. El Pais US сообщает, что официальный FIFA Fan Festival в Los Angeles Memorial Coliseum пройдет 11-14 июня с платным входом, а затем город развернет сеть районных площадок.

Среди подтвержденных точек названы Original Farmers Market, Union Station, Hansen Dam Lake, Magic Johnson Park, Whittier Narrows, Venice Beach и Fairplex. У каждой площадки свои даты, поэтому болельщикам важно планировать не только место, но и конкретный день.

