insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('204e7600-2c60-5d34-b9c8-cf122d56c7c1', 'en', 'dallas-world-cup-transport-mobility-maps', 'Dallas publishes World Cup mobility maps for stadium, Fan Festival and IBC trips', 'Dallas 2026 is pointing fans to GoPass, transit links, road closures and pedestrian-priority corridors across North Texas.', 'Dallas 2026 has turned its regional mobility plan into a fan-facing planning page. The host committee highlights GoPass for transit ticketing and trip planning, maps connecting Dallas Stadium, Fair Park''s FIFA Fan Festival, the International Broadcast Center, rail lines and walking routes, and notes downtown Dallas road closures tied to tournament operations.

The Dallas page frames mobility as a regional system rather than a single stadium route. Matches are in Arlington, the Fan Festival is at Fair Park in Dallas, the International Broadcast Center is downtown and team base camps sit in other North Texas locations.

GoPass is presented as the digital tool for tickets, route planning, live vehicle tracking and service alerts across agencies such as DART, Trinity Metro and DCTA. For visitors, that matters because a match-day plan may cross multiple transit systems.

Dallas 2026 says the maps show planned road closures, special transit services and pedestrian-priority corridors. One downtown note says FIFA plans to fully close Griffin Street between Canton Street and Ceremonial Drive from May 26 until July 23.

CupMate users should avoid saving one generic Dallas route for everything. The practical setup is three saved places: Dallas Stadium, Fair Park Fan Festival and the downtown IBC area, each with its own transit option, rideshare backup and walking segment.', 'Dallas publishes World Cup mobility maps for stadium, Fan Festival and IBC trips', 'Dallas 2026 is pointing fans to GoPass, transit links, road closures and pedestrian-priority corridors across North Texas.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('204e7600-2c60-5d34-b9c8-cf122d56c7c1', 'ru', 'dallas-karty-transporta-chm-stadion-fan-festival', 'Dallas опубликовал mobility maps для стадиона, Fan Festival и IBC', 'Dallas 2026 указывает болельщикам на GoPass, маршруты, перекрытия и pedestrian corridors по всему North Texas.', 'Dallas 2026 превратил региональный транспортный план в практическую страницу для болельщиков. Организаторы выделяют GoPass как инструмент для билетов, маршрутов, отслеживания транспорта и service alerts в системе North Texas.

Важно, что это не один маршрут к стадиону. Матчи проходят в Arlington, FIFA Fan Festival расположен в Fair Park в Dallas, International Broadcast Center — в центре города, а тренировочные базы находятся в других точках региона. Поэтому один сохраненный маршрут не решает всю поездку.

В CupMate лучше создать отдельные точки: Dallas Stadium, Fair Park Fan Festival и downtown/IBC area. Для каждой стоит сохранить transit-вариант, rideshare backup и пеший участок, особенно с учетом перекрытий с конца мая до конца июля.', 'Dallas опубликовал mobility maps для стадиона, Fan Festival и IBC', 'Dallas 2026 указывает болельщикам на GoPass, маршруты, перекрытия и pedestrian corridors по всему North Texas.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;

insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('6e6fbd11-53d1-5c82-849f-60b61e5c0423', 'news', 'published', 'Teams', null, 'https://www.fifa.com/en/articles/qatar-announce-preliminary-squad', '2026-05-13T12:00:00+00:00') on conflict (id) do update set status = excluded.status, category = excluded.category, source_url = excluded.source_url, published_at = excluded.published_at;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('6e6fbd11-53d1-5c82-849f-60b61e5c0423', 'en', 'qatar-preliminary-world-cup-squad-group-b', 'Qatar''s preliminary World Cup squad gives Group B fans early planning clues', 'Julen Lopetegui has named a 34-player preliminary Qatar squad, with Akram Afif, Almoez Ali and veteran Sebastian Soria among the names to watch.', 'Qatar''s World Cup preparation has moved from qualification story to roster planning. FIFA reported that Julen Lopetegui named a 34-player preliminary squad, with Akram Afif, Almoez Ali and Sebastian Soria included before Qatar''s Group B matches in the Bay Area, Vancouver and Seattle.

The preliminary list keeps Qatar built around familiar tournament names while leaving room for a final cut before FIFA receives the 26-player squads on June 2. For supporters, the key is not treating the 34 names as final, but it is enough to begin setting player alerts and match expectations.

Sebastian Soria''s inclusion gives Qatar a rare age-record angle. If he appears in North America, he would move past Roger Milla as the oldest outfield player in men''s World Cup history. That kind of storyline can turn a group match into a broader neutral-fan draw.

Qatar supporters are looking at a compact but border-crossing West Coast campaign: Bay Area, Vancouver, then Seattle. The distances are manageable compared with some groups, but the Canada leg still means passport checks, hotel timing and flight or rail buffers matter.

CupMate users following Qatar should save all three Group B cities now, then update the squad card after the June 2 final list. The practical plan is to keep Vancouver flexible because a co-host match can bring extra ticket, hotel and fan-zone demand.', 'Qatar''s preliminary World Cup squad gives Group B fans early planning clues', 'Julen Lopetegui has named a 34-player preliminary Qatar squad, with Akram Afif, Almoez Ali and veteran Sebastian Soria among the names to watch.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('6e6fbd11-53d1-5c82-849f-60b61e5c0423', 'ru', 'katar-predvaritelnyy-sostav-chm-marshrut-gruppy-b', 'Предварительный состав Катара дает болельщикам ориентиры по группе B', 'Хулен Лопетеги назвал расширенный состав Катара из 34 игроков, включая Акрома Афифа, Альмоэза Али и ветерана Себастьяна Сорию.', 'Подготовка Катара к Чемпионату мира перешла от темы квалификации к конкретике состава. FIFA сообщила, что Хулен Лопетеги назвал предварительный список из 34 игроков, где есть Акрам Афиф, Альмоэз Али и Себастьян Сория. Финальная заявка на 26 игроков должна быть подтверждена после подачи списков в FIFA 2 июня.

Для болельщиков это уже достаточно данных, чтобы строить ожидания по матчам и маршруту. Катар сыграет со Швейцарией в Bay Area 13 июня, с Канадой в Vancouver 18 июня и с Bosnia and Herzegovina в Seattle 24 июня. Это удобный западный маршрут, но матч в Канаде требует отдельного планирования документов и транспорта.

Отдельная история — Сория. Если он выйдет на поле, он может побить возрастной рекорд Roger Milla для полевых игроков на мужском ЧМ. В CupMate такой матч стоит отмечать не только как игру Катара, но и как потенциальное событие для нейтральных фанатов.', 'Предварительный состав Катара дает болельщикам ориентиры по группе B', 'Хулен Лопетеги назвал расширенный состав Катара из 34 игроков, включая Акрома Афифа, Альмоэза Али и ветерана Себастьяна Сорию.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;

