insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('b00ef7e4-bf64-5365-8f1e-44614c646e19', 'en', 'korea-republic-world-cup-squad-group-c-route', 'Korea Republic squad news sets up a practical Group C route for fans', 'Hong Myungbo has named Korea Republic''s 26-player World Cup squad, led by Son Heungmin, Kim Minjae and other experienced names.', 'Korea Republic''s World Cup squad is now public. FIFA reported that Hong Myungbo selected a 26-player group led by Son Heungmin, Kim Minjae, Hwang Heechan, Lee Kangin and other familiar names before two matches in Guadalajara and a group closer in Monterrey.

