insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('b86300cc-3430-5b61-b894-188c738bb8b2', 'en', 'japan-world-cup-squad-mitoma-fitness-watch', 'Japan squad watch puts Mitoma''s absence at the center of fan expectations', 'Hajime Moriyasu has named Japan''s 26-player World Cup squad, with Kaoru Mitoma missing out and several recently injured players included.', 'Japan''s World Cup squad brings both clarity and a major talking point. FIFA reported that Hajime Moriyasu named his 26-player group, leaving out injured Kaoru Mitoma while including Wataru Endo, Ko Itakura and Takehiro Tomiyasu before Group F matches in Dallas and Monterrey.

