insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('b86300cc-3430-5b61-b894-188c738bb8b2', 'ru', 'yaponiya-sostav-chm-otsutstvie-mitoma', 'Состав Японии: отсутствие Mitoma меняет ожидания болельщиков', 'Хадзимэ Мориясу назвал заявку Японии из 26 игроков: Kaoru Mitoma не попал в состав, но ряд игроков после травм включен.', 'Состав Японии на Чемпионат мира одновременно дал ясность и оставил крупную тему для обсуждения. FIFA сообщила, что Хадзимэ Мориясу назвал 26 игроков, не включив травмированного Kaoru Mitoma. При этом в заявке есть Wataru Endo, Ko Itakura и Takehiro Tomiyasu.

