insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('e446531d-1237-5769-bd2e-2b5ce70d5f0e', 'en', 'haiti-world-cup-squad-boston-return', 'Haiti''s World Cup squad turns a 52-year return into a Boston fan-planning moment', 'Haiti have named their 26-player World Cup squad for a first finals appearance since 1974, with Johny Placide and Duckens Nazon among the leaders.', 'Haiti''s first World Cup in 52 years now has a named squad. FIFA reported that Sebastien Migne selected a 26-player group led by Johny Placide, Ricardo Ade, Carlens Arcus, Leverton Pierre, Danley Jean Jacques and Duckens Nazon for Group C matches against Scotland, Brazil and Morocco.

Haiti have not played at a World Cup since 1974, so this squad announcement is more than a roster note. It gives supporters, diaspora groups and neutral fans a concrete team list for one of the tournament''s strongest comeback stories.

Haiti open against Scotland at Boston Stadium on June 13, then fly across the country to face Brazil at Los Angeles Stadium on June 19, before closing against Morocco at Atlanta Stadium on June 24.

The squad includes established leaders and attackers who shaped qualification, but the bigger planning issue is momentum. If Haiti take anything from the opener, the Los Angeles and Atlanta legs could see a late surge in fan interest.

CupMate users should save Haiti as a full multi-city itinerary, not just a single emotional opener. Add refundable travel where possible, watch official ticket channels only and keep group-meetup plans near transit rather than stadium road traffic.', 'Haiti''s World Cup squad turns a 52-year return into a Boston fan-planning moment', 'Haiti have named their 26-player World Cup squad for a first finals appearance since 1974, with Johny Placide and Duckens Nazon among the leaders.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;
