insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('ccec627d-5bc6-521d-b18e-83a897819071', 'news', 'published', 'Tickets', null, 'https://gpcustomersupportfwc2026.tickets.fifa.com/hc/en-gb/articles/36037048232733-1-What-apps-are-available-for-download-for-the-FIFA-World-Cup-2026', '2026-05-20T12:00:00+00:00') on conflict (id) do update set status = excluded.status, category = excluded.category, source_url = excluded.source_url, published_at = excluded.published_at;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('ccec627d-5bc6-521d-b18e-83a897819071', 'en', 'world-cup-mobile-ticket-app-phone-readiness', 'World Cup mobile ticket app makes phone readiness part of match-day planning', 'FIFA''s ticketing support now points fans to dedicated World Cup 2026 apps, making phone setup, account access and battery planning part of stadium entry.', 'FIFA''s ticketing support has moved mobile access into the practical planning layer for World Cup 2026. The official support guidance points fans to tournament apps, which means match-day readiness is no longer only about reaching the stadium; it is also about account access, phone battery, connectivity and keeping tickets available at the gate.

Mobile ticketing changes the stress points of a World Cup day. A fan can have the right ticket and still create a delay if the app is not installed, the account cannot be accessed or the phone is almost dead before gates open.

The practical move is to treat app setup like passport or hotel confirmation. Install the official app, sign in, verify ticket visibility and understand transfer rules before leaving for the stadium.

World Cup groups often move in pieces: one person handles tickets, another books transit and others arrive from different hotels. Mobile tickets make coordination cleaner only if everyone knows who has access and when transfers must happen.

CupMate users should add a mobile-ticket readiness task to every match itinerary. The checklist should sit next to transit, bag policy and gate-time reminders.', 'World Cup mobile ticket app makes phone readiness part of match-day planning', 'FIFA''s ticketing support now points fans to dedicated World Cup 2026 apps, making phone setup, account access and battery planning part of stadium entry.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('ccec627d-5bc6-521d-b18e-83a897819071', 'ru', 'mobilnoe-prilozhenie-biletov-chm-phone-readiness', 'Мобильное приложение билетов ЧМ делает телефон частью match-day checklist', 'Ticketing support FIFA указывает на приложения ЧМ-2026, поэтому настройка телефона, доступ к аккаунту и батарея становятся частью входа на стадион.', 'Ticketing support FIFA переводит mobile access в практический слой планирования ЧМ-2026. Официальная инструкция указывает болельщикам на tournament apps, а значит готовность к матчу теперь включает не только дорогу к стадиону, но и доступ к аккаунту, заряд телефона, связь и доступность билетов у входа.

Mobile ticketing меняет точки риска. Билет может быть правильным, но вход задержится, если приложение не установлено, аккаунт не открывается или телефон почти разряжен перед gate time.

В CupMate к каждому матчу стоит добавить mobile-ticket readiness: установить официальный app, войти заранее, проверить видимость билета, понять transfer rules и подтвердить, кто в группе контролирует каждый билет.', 'Мобильное приложение билетов ЧМ делает телефон частью match-day checklist', 'Ticketing support FIFA указывает на приложения ЧМ-2026, поэтому настройка телефона, доступ к аккаунту и батарея становятся частью входа на стадион.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;

insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('fe4afe8a-1e39-5cf6-8fd8-bc73e445ea01', 'news', 'published', 'Travel', null, 'https://www.theguardian.com/us-news/2026/may/19/new-york-hotel-workers-world-cup-union-deal', '2026-05-19T12:00:00+00:00') on conflict (id) do update set status = excluded.status, category = excluded.category, source_url = excluded.source_url, published_at = excluded.published_at;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('fe4afe8a-1e39-5cf6-8fd8-bc73e445ea01', 'en', 'new-york-hotel-labor-deal-world-cup-lodging', 'New York hotel labor deal lowers one World Cup lodging risk', 'A New York hotel union deal reported by Reuters through The Guardian removes one uncertainty for fans planning stays around World Cup matches and the final.', 'One lodging risk around the New York New Jersey World Cup window has eased. Reuters, carried by The Guardian, reported that New York City hotel workers reached a labor deal before the tournament, reducing uncertainty for travelers who need rooms around regional matches, fan events and the final.

A labor deal does not make New York hotels cheap or easy to book, but it removes one category of uncertainty. For World Cup visitors, that matters because lodging is often the largest non-ticket cost in a New York New Jersey itinerary.

The deal lowers disruption risk, but demand around MetLife Stadium matches, the final, fan events and summer tourism can still push prices and minimum stays. Fans should compare refundable rates, transit access and late check-in policies.

New York can draw fans who never enter the stadium: watch-party travelers, sponsor-event guests, media and neutral visitors. That broader demand can affect rooms across Manhattan, Queens, Brooklyn, Newark and Jersey City.

CupMate users should connect lodging choices to actual match-day transport. A stable hotel deal helps, but a room still needs a realistic route to MetLife, the Fan Hub or a watch venue.', 'New York hotel labor deal lowers one World Cup lodging risk', 'A New York hotel union deal reported by Reuters through The Guardian removes one uncertainty for fans planning stays around World Cup matches and the final.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('fe4afe8a-1e39-5cf6-8fd8-bc73e445ea01', 'ru', 'new-york-hotel-labor-deal-snizhaet-risk-prozhivaniya', 'Сделка отелей New York снижает один риск проживания на ЧМ', 'Соглашение гостиничного профсоюза, о котором Reuters сообщил через The Guardian, убирает одну неопределенность для поездок на матчи и финал.', 'Один риск проживания в период New York New Jersey World Cup снизился. Reuters через The Guardian сообщил, что работники гостиниц New York City достигли трудового соглашения до турнира, уменьшая неопределенность для болельщиков, которым нужны номера вокруг матчей, фан-событий и финала.

Сделка не делает отели дешевыми или простыми для бронирования, но убирает один тип disruption risk. Для гостей ЧМ это важно, потому что жилье часто является крупнейшей статьей расходов после билетов.

В CupMate отель нужно связывать с реальным match-day transport. Даже при стабильной labor situation номер должен иметь понятный маршрут к MetLife, Fan Hub или watch venue, а группы должны держать refundable options там, где это возможно.', 'Сделка отелей New York снижает один риск проживания на ЧМ', 'Соглашение гостиничного профсоюза, о котором Reuters сообщил через The Guardian, убирает одну неопределенность для поездок на матчи и финал.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;

