insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('f13884d8-57bd-57c3-8511-40a471684262', 'en', 'iran-training-camp-azmoun-group-g-fluid', 'Iran training camp and Azmoun absence keep Group G plans fluid', 'AP''s Iran World Cup update highlights Sardar Azmoun''s absence and team travel context, reinforcing why Group G fans should keep lineup and logistics alerts on.', 'Iran''s Group G planning remains fluid after AP reported on the team''s World Cup preparations, including the absence of Sardar Azmoun from the squad picture and the wider travel context around the team. For supporters, the update reinforces that lineup expectations, training news and match-day logistics should be watched together.

