insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('f13884d8-57bd-57c3-8511-40a471684262', 'ru', 'iran-training-camp-azmoun-gruppa-g', 'Тренировочный лагерь Ирана и отсутствие Azmoun оставляют группу G гибкой', 'Обновление AP по Ирану выделяет отсутствие Sardar Azmoun и контекст подготовки команды, поэтому фанатам группы G нужны lineup и logistics alerts.', 'Планирование Ирана в группе G остается подвижным после обновления AP о подготовке команды к Чемпионату мира, включая отсутствие Sardar Azmoun в картине состава и более широкий travel context вокруг команды. Для болельщиков это сигнал: ожидания по lineup, training news и match-day logistics нужно отслеживать вместе.

Иран играет в группе с Belgium, Egypt и New Zealand, а первые два матча особенно важны для фанатских встреч и поездок. Если атакующие роли изменятся, изменятся и watch-party narratives, и интерес нейтральных болельщиков.

В CupMate болельщикам Ирана стоит закрепить Group G alerts, держать official ticket и travel proof вместе и воспринимать Seattle-финал как отдельный logistics block после матчей в Los Angeles.', 'Тренировочный лагерь Ирана и отсутствие Azmoun оставляют группу G гибкой', 'Обновление AP по Ирану выделяет отсутствие Sardar Azmoun и контекст подготовки команды, поэтому фанатам группы G нужны lineup и logistics alerts.') on conflict (article_id, language_code) do update set slug = excluded.slug, title = excluded.title, excerpt = excluded.excerpt, body = excluded.body, seo_title = excluded.seo_title, seo_description = excluded.seo_description;
